SELECT * FROM knowledge_chunks WHERE
content LIKE CONCAT('%', #{term}, '%')
ORDER BY (
(CASE WHEN content LIKE CONCAT('%', #{term}, '%') THEN 100 ELSE 0 END) (CASE WHEN content LIKE CONCAT('%', #{term}, '%') THEN 10 ELSE 0 END) (CASE WHEN content LIKE CONCAT('%', #{term}, '%') THEN 1 ELSE 0 END)
) DESC LIMIT #{limit}

SELECT * FROM knowledge_chunks

    (

        content LIKE CONCAT('%', #{term}, '%')

    )

        AND category IN

            #{category}



        AND software IN

            #{softwareName}



        AND source_type IN

            #{sourceType}



        AND source_id IN

            #{sourceId}



ORDER BY
(

        (CASE WHEN content LIKE CONCAT('%', #{term}, '%') THEN 100 ELSE 0 END)
        (CASE WHEN content LIKE CONCAT('%', #{term}, '%') THEN 10 ELSE 0 END)
        (CASE WHEN content LIKE CONCAT('%', #{term}, '%') THEN 1 ELSE 0 END)

)
DESC
LIMIT #{limit}
